'use strict';

/**
* Compute the number of non-`NaN` elements in a strided array.
*
* @module @stdlib/blas/ext/base/gnancount
*
* @example
* import gnancount from '@stdlib/blas/ext/base/gnancount';
*
* var x = [ 1.0, -2.0, NaN, 2.0 ];
*
* var v = gnancount( x.length, x, 1 );
* // returns 3
*
* @example
* import gnancount from '@stdlib/blas/ext/base/gnancount';
*
* var x = [ 2.0, 1.0, 2.0, -2.0, -2.0, 2.0, 3.0, 4.0, NaN, NaN ];
*
* var v = gnancount.ndarray( 5, x, 2, 1 );
* // returns 4
*/

// MODULES //

import setReadOnly from '@stdlib/utils/define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;

// exports: { "ndarray": "main.ndarray" }
